"use client";

/**
 * Opener for the `fullScreenEditor` overlay.
 *
 * - `useOpenFullScreenMarkdownEditorBridge()` — imperative hook. Call to open with typed options;
 *   returns a handle with a `close()` method.
 * - `<FullScreenMarkdownEditorBridgeController />` — declarative wrapper. Mount to open,
 *   unmount to close. Equivalent ergonomics to rendering a normal component.
 *
 * Generated by scripts/generate-overlay-controller.ts (`openers` mode).
 * Hand-edit freely after the initial seed; the script will not re-emit a
 * file that already exists unless invoked with --force.
 */

import { useCallback, useEffect } from "react";
import { useAppDispatch } from "@/lib/redux/hooks";
import { closeOverlay, openOverlay } from "@/lib/redux/slices/overlaySlice";

const OVERLAY_ID = "fullScreenEditor" as const;

export interface OpenFullScreenMarkdownEditorBridgeOptions {
  /** Optional stable instance id. Omit to spawn a fresh instance. */
  instanceId?: string;
  content?: string;
  /** TODO: tighten to `FullScreenEditorMode` once that type is imported. */
  mode?: unknown;
  conversationId?: string;
  messageId?: string;
  /** TODO callback — wire via callback registry in stage 3. */
  onSave?: (...args: unknown[]) => void;
  /** TODO: tighten to `TabId[]` once that type is imported. */
  tabs?: unknown;
  /** TODO: tighten to `TabId` once that type is imported. */
  initialTab?: unknown;
  analysisData?: Record<string, unknown>;
  title?: string;
  description?: string;
  showSaveButton?: boolean;
  showCopyButton?: boolean;
}

export interface FullScreenMarkdownEditorBridgeHandle {
  instanceId: string;
  close: () => void;
}

export function useOpenFullScreenMarkdownEditorBridge() {
  const dispatch = useAppDispatch();
  return useCallback(
    (opts: OpenFullScreenMarkdownEditorBridgeOptions = {}): FullScreenMarkdownEditorBridgeHandle => {
      const instanceId = opts.instanceId ?? `fullScreenEditor-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      dispatch(
        openOverlay({
          overlayId: OVERLAY_ID,
          instanceId,
          data: {
            content: opts.content,
            mode: opts.mode,
            conversationId: opts.conversationId,
            messageId: opts.messageId,
            onSave: opts.onSave,
            tabs: opts.tabs,
            initialTab: opts.initialTab,
            analysisData: opts.analysisData,
            title: opts.title,
            description: opts.description,
            showSaveButton: opts.showSaveButton,
            showCopyButton: opts.showCopyButton,
          },
        }),
      );
      return {
        instanceId,
        close: () => dispatch(closeOverlay({ overlayId: OVERLAY_ID, instanceId })),
      };
    },
    [dispatch],
  );
}

/**
 * Declarative form. Renders nothing visible; opens the overlay on mount,
 * closes it on unmount. Use this when a caller wants to express overlay
 * state declaratively (the way they'd render a normal component).
 */
export function FullScreenMarkdownEditorBridgeController(props: OpenFullScreenMarkdownEditorBridgeOptions): null {
  const open = useOpenFullScreenMarkdownEditorBridge();
  useEffect(() => {
    const handle = open(props);
    return () => handle.close();
  }, [open, props.content, props.mode, props.conversationId, props.messageId, props.onSave, props.tabs, props.initialTab, props.analysisData, props.title, props.description, props.showSaveButton, props.showCopyButton]);
  return null;
}
